#include <string>
#include <unordered_map>

class SORTracker {
public:
    SORTracker() {}

    void add(std::string name, int score) {
        auto it = std::lower_bound(m_locations.begin(), m_locations.end(), name, [&](const std::string& lhs, const std::string& rhs) {
            return lhs < rhs;
        });
        m_locations.insert(it, {name, score});
    }

    string get() {
        if (m_locations.empty()) {
            return "";
        }
        auto it = std::lower_bound(m_locations.begin(), m_locations.end(), "");
        return *(it - 1);
    }

private:
    std::unordered_map<std::string, std::pair<std::string, int>> m_locations;
};
```

